checker_dsl:
EXISTS (`reference equality test RET`) {
  AND {
    (`the type of the left operand of RET is a BoxedType`),
    (`the type of the right operand of RET is a BoxedType`),
    NOT {
      EXISTS (`operand O`) {
        AND {
          (`O is an operand of RET`),
          (`the type of O is a RefType`),
          (`the qualified name of the type of O is "java.lang.Boolean"`)
        }
      }
    }
  }
}
